postToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
New-Item -ItemType Directory -Force -Path .vstack/logs | Out-Null
Add-Content -Path .vstack/logs/hook-post-commit.jsonl -Value $inputText
if ($inputText -notmatch 'git (commit|push|merge|rebase)') {
  exit 0
}
if ((git rev-parse --git-dir 2>$null) -and (git diff --cached | Select-String -Pattern 'AKIA[0-9A-Z]{16}|ghp_[A-Za-z0-9]{36,}|-----BEGIN (RSA|EC|OPENSSH) PRIVATE KEY-----' -Quiet)) {
  Add-Content -Path .vstack/logs/hook-security-alerts.log -Value 'possible-secrets-detected-in-staged-diff'
}
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -eq 'enforce') {
  if (Get-Command gitleaks -ErrorAction SilentlyContinue) {
    gitleaks dir . --no-banner --redact *> $null
    if ($LASTEXITCODE -ne 0) {
      Add-Content -Path .vstack/logs/hook-security-alerts.log -Value 'gitleaks-reported-findings'
    }
  } else {
    Add-Content -Path .vstack/logs/hook-security-alerts.log -Value 'gitleaks-not-installed'
  }
}
